module pe(
    input clk,
    input rst,
    input [31:0] a,
    input [31:0] b,
    output reg [31:0] c
);

    reg [31:0] partial_sum;

    always @(posedge clk) begin
        if (rst) begin
            partial_sum <= 0;
            c <= 0;
        end else begin
            partial_sum <= partial_sum + (a * b);
            c <= partial_sum;
        end
    end

endmodule
